window.SLIDES = [{"index":1,"folder":"01_Intro","name":"Intro","items":[{"type":"image","name":"01_the-black-box.svg","src":"/Slides_Datasets/01_Intro/01_the-black-box.svg"},{"type":"text","name":"intro.txt","text":"INSIDE THE BLACK BOX\nSchmidgen, on Simondon's politics of technology.\n\nA machine arrives polished and mute.\nWe admire the surface. We never open it.\n\"First a gothic cathedral, then a kitchen.\" (Barthes)\n\nThis canvas is the inside of the box:\nraw, scattered, unrationalized.\nYour job begins here.\n"}]},{"index":2,"folder":"02_Cybernetics_1951","name":"Cybernetics 1951","items":[{"type":"image","name":"citroen-goddess.svg","src":"/Slides_Datasets/02_Cybernetics_1951/citroen-goddess.svg"},{"type":"image","name":"machine-show.svg","src":"/Slides_Datasets/02_Cybernetics_1951/machine-show.svg"},{"type":"text","name":"note.txt","text":"THE FASCINATION ERROR\n\nThe 1950s adored robots and \"mechanical slaves.\"\nSimondon: this is a misunderstanding of progress.\n\nAutomation is not perfection.\nA machine that decides everything is a CLOSED machine.\nWorship of the closed object = the black box, sealed shut.\n"}]},{"index":3,"folder":"03_Open_Machine","name":"Open Machine","items":[{"type":"image","name":"margin-of-indetermination.svg","src":"/Slides_Datasets/03_Open_Machine/margin-of-indetermination.svg"},{"type":"text","name":"note.txt","text":"OPENNESS, NOT AUTOMATION\n\n\"The criterion of technical perfection is\nopenness and flexibility, not automation.\" — Simondon\n\nThe good machine keeps a margin of indetermination:\na gap where information can still enter,\nwhere a human can still tune, regulate, interpret.\n\nOpen the box. Keep it open.\n"},{"type":"image","name":"open-vs-closed.svg","src":"/Slides_Datasets/03_Open_Machine/open-vs-closed.svg"}]},{"index":4,"folder":"04_Democratic_Orchestra","name":"Democratic Orchestra","items":[{"type":"image","name":"conductor.svg","src":"/Slides_Datasets/04_Democratic_Orchestra/conductor.svg"},{"type":"text","name":"note.txt","text":"THE HUMAN AS CONDUCTOR\n\n\"Man is among the machines that work with him.\"\n\nNot master, not slave — interpreter.\nThe permanent organizer of an orchestra of open machines,\ntuning the relationships between them.\n\nThis is a cultural task. A political one.\n"}]},{"index":5,"folder":"05_Black-Boxed_Interfaces","name":"Black Boxed Interfaces","items":[{"type":"image","name":"glossy-slab.svg","src":"/Slides_Datasets/05_Black-Boxed_Interfaces/glossy-slab.svg"},{"type":"image","name":"halftone-warning.svg","src":"/Slides_Datasets/05_Black-Boxed_Interfaces/halftone-warning.svg"},{"type":"text","name":"warning.txt","text":"THE TODAY PROBLEM\n\nOur screens are gorgeous and sealed.\nReady-made, black-boxed interfaces.\nThey please us — and deny us the margin to regulate them.\n\nThe black box came back, glossier than ever.\nSo: who rationalizes the data now?\nYou. And the machine you are about to question.\n"}]}];
